
// components/EmailFormModal.jsx
import React, { useState, useEffect, useRef } from 'react';
import styled, { ThemeProvider, keyframes, css } from 'styled-components';

// --- Animations ---
const slideUpMobile = keyframes`
  from { transform: translateY(100%); opacity: 0; }
  to { transform: translateY(0); opacity: 1; }
`;

const hologramPop = keyframes`
  0% { opacity: 0; transform: scale(0.95) translateY(10px); filter: blur(5px); }
  100% { opacity: 1; transform: scale(1) translateY(0); filter: blur(0); }
`;

// --- ✨ THEME DEFINITIONS ✨ ---
const darkTheme = {
  mode: 'dark',
  bg: 'rgba(23, 25, 35, 0.85)',
  text: '#e2e8f0',
  title: '#ffffff',
  border: 'rgba(255, 255, 255, 0.1)',
  inputBg: 'rgba(0, 0, 0, 0.3)',
  inputFocusBg: 'rgba(0, 0, 0, 0.5)',
  placeholder: 'rgba(255, 255, 255, 0.3)',
  headerBorder: 'rgba(255, 255, 255, 0.08)',
  iconBg: 'rgba(255, 255, 255, 0.1)',
  buttonHoverBg: 'rgba(255, 255, 255, 0.1)',
  minimizedHover: 'rgba(255, 255, 255, 0.05)',
  shadow: '0 25px 50px -12px rgba(0, 0, 0, 0.5)',
  labelColor: 'rgba(255, 255, 255, 0.6)',
  subText: '#818cf8',
  footerBg: 'rgba(0, 0, 0, 0.2)',
  closeBtnHover: 'rgba(239, 68, 68, 0.2)',
  closeBtnColor: '#ef4444'
};

const lightTheme = {
  mode: 'light',
  bg: 'rgba(255, 255, 255, 0.95)', // ☁️ High opacity white
  text: '#4a5568',                // 🎯 The specific slate color you asked for
  title: '#1a202c',               // Darker black/grey for titles
  border: 'rgba(0, 0, 0, 0.1)',   // Subtle grey border
  inputBg: '#edf2f7',             // Light grey input background
  inputFocusBg: '#ffffff',        // Pure white on focus
  placeholder: '#a0aec0',
  headerBorder: 'rgba(0, 0, 0, 0.06)',
  iconBg: '#ffffff',
  buttonHoverBg: 'rgba(0, 0, 0, 0.05)',
  minimizedHover: 'rgba(0, 0, 0, 0.03)',
  shadow: '0 20px 40px -12px rgba(0, 0, 0, 0.15), 0 0 0 1px rgba(0,0,0,0.05)',
  labelColor: '#718096',          // Cool grey for labels
  subText: '#5a67d8',             // Indigo
  footerBg: '#f7fafc',
  closeBtnHover: 'rgba(239, 68, 68, 0.1)',
  closeBtnColor: '#dc2626'
};

// --- Styled Components ---

const DraggablePanel = styled.div`
  position: fixed;
  z-index: 10000;
  
  /* Apply Theme Props */
  background: ${props => props.theme.bg};
  border: 1px solid ${props => props.theme.border};
  box-shadow: ${props => props.theme.shadow};
  color: ${props => props.theme.text};

  backdrop-filter: blur(20px) saturate(180%);
  -webkit-backdrop-filter: blur(20px) saturate(180%);

  display: ${props => props.show ? 'flex' : 'none'};
  flex-direction: column;
  overflow: hidden;
  
  transition: width 0.3s, height 0.3s, border-radius 0.3s, opacity 0.3s, background 0.3s;

  /* Desktop */
  ${props => !props.isMobile && css`
    width: ${props.minimized ? '280px' : '400px'};
    height: ${props.minimized ? '68px' : '620px'};
    border-radius: 20px;
    left: ${props.x}px;
    top: ${props.y}px;
    
    transition: ${props.isDragging ? 'none' : 'all 0.3s cubic-bezier(0.25, 0.8, 0.25, 1)'};
    
    ${props.isDragging && css`
      box-shadow: 0 40px 80px rgba(0,0,0,0.2);
      transform: scale(1.02);
      cursor: grabbing;
    `}

    animation: ${hologramPop} 0.5s cubic-bezier(0.2, 0.8, 0.2, 1);
  `}

  /* Mobile */
  ${props => props.isMobile && css`
    left: 0; right: 0; bottom: 0;
    width: 100%;
    max-height: ${props.minimized ? '80px' : '90vh'};
    border-radius: 24px 24px 0 0;
    animation: ${slideUpMobile} 0.4s cubic-bezier(0.2, 0.8, 0.2, 1);
    border-bottom: none;
  `}
`;

const Header = styled.div`
  padding: 16px 20px;
  background: linear-gradient(180deg, ${props => props.theme.mode === 'light' ? 'rgba(255,255,255,0.6)' : 'rgba(255,255,255,0.03)'} 0%, rgba(255,255,255,0) 100%);
  border-bottom: 1px solid ${props => props.theme.headerBorder};
  display: flex;
  align-items: center;
  justify-content: space-between;
  flex-shrink: 0;
  user-select: none;
  
  ${props => !props.isMobile && css`
    cursor: grab;
    &:active { cursor: grabbing; }
  `}
`;

const HeaderContent = styled.div`
  display: flex;
  align-items: center;
  gap: 12px;
  pointer-events: none;
`;

const IconWrapper = styled.div`
  width: 38px;
  height: 38px;
  display: flex;
  align-items: center;
  justify-content: center;
  background: ${props => props.theme.iconBg};
  border: 1px solid ${props => props.theme.headerBorder};
  border-radius: 10px;
  font-size: 18px;
  box-shadow: 0 2px 8px rgba(0, 0, 0, 0.05);
  color: ${props => props.theme.title};
`;

const Title = styled.h3`
  margin: 0;
  font-size: 15px;
  font-weight: 700;
  color: ${props => props.theme.title};
  letter-spacing: -0.2px;
`;

const Subtitle = styled.div`
  font-size: 11px;
  color: ${props => props.theme.subText};
  font-weight: 600;
  margin-top: 1px;
`;

const HeaderActions = styled.div`
  display: flex;
  gap: 6px;
`;

const HeaderButton = styled.button`
  background: transparent;
  border: 1px solid transparent;
  width: 28px;
  height: 28px;
  display: flex;
  align-items: center;
  justify-content: center;
  border-radius: 8px;
  cursor: pointer;
  font-size: 16px;
  color: ${props => props.theme.labelColor};
  transition: all 0.2s;
  
  &:hover {
    background: ${props => props.danger ? props.theme.closeBtnHover : props.theme.buttonHoverBg};
    color: ${props => props.danger ? props.theme.closeBtnColor : props.theme.title};
    border-color: ${props => props.theme.headerBorder};
  }
`;

const FormContent = styled.div`
  flex: 1;
  overflow-y: auto;
  padding: 24px;
  
  &::-webkit-scrollbar { width: 5px; }
  &::-webkit-scrollbar-track { background: transparent; }
  &::-webkit-scrollbar-thumb { 
    background: ${props => props.theme.labelColor}; 
    opacity: 0.2;
    border-radius: 10px; 
  }
`;

const Form = styled.form`
  display: flex;
  flex-direction: column;
  gap: 18px;
`;

const FormGroup = styled.div`
  display: flex;
  flex-direction: column;
  gap: 6px;
`;

const Label = styled.label`
  font-size: 11px;
  font-weight: 700;
  color: ${props => props.theme.labelColor};
  text-transform: uppercase;
  letter-spacing: 0.8px;
  margin-left: 2px;
`;

