// components/EmailAgent.js

// ============= EMAIL AGENT (Free Tier - EmailJS) =============
export const EmailAgent = {
    // EmailJS Configuration
    config: {
      serviceId: 'service_xe6alve',      // Replace
      templateId: 'template_k2u1z0k',    // Replace
      publicKey: 'ANZYSfODJvj2-066t'       // Replace
    },
  
    // Initialize EmailJS
    init() {
      if (typeof window !== 'undefined' && !window.emailjs) {
        const script = document.createElement('script');
        script.src = 'https://cdn.jsdelivr.net/npm/@emailjs/browser@3/dist/email.min.js';
        script.onload = () => {
          window.emailjs.init(this.config.publicKey);
          console.log('📧 EmailJS initialized');
        };
        document.head.appendChild(script);
      }
    },
  
    // Conversation state for collecting info
    conversationState: {
      isCollecting: false,
      inquiryType: null,
      data: {},
      currentStep: 0
    },
  
    // Email collection flows
    inquiryFlows: {
      HIRE: {
        steps: ['name', 'email', 'company', 'phone', 'message'],
        prompts: {
          name: "What's your name?",
          email: "What's your email address?",
          company: "Which company are you from?",
          phone: "Your phone number? (or say 'skip')",
          message: "Tell me about the opportunity or role."
        },
        confirmMessage: (data) => 
          `Perfect! I'll send this to Laxman: ${data.name} from ${data.company} regarding a job opportunity. Correct?`
      },
  
      COLLABORATE: {
        steps: ['name', 'email', 'project', 'message'],
        prompts: {
          name: "What's your name?",
          email: "Your email?",
          project: "What's the project about?",
          message: "Any additional details?"
        },
        confirmMessage: (data) => 
          `Got it! Sending collaboration request from ${data.name} about ${data.project}. Confirm?`
      },
  
      QUESTION: {
        steps: ['name', 'email', 'message'],
        prompts: {
          name: "Your name?",
          email: "Your email?",
          message: "What's your question?"
        },
        confirmMessage: (data) => 
          `Okay! Sending your question from ${data.name}. Ready to send?`
      }
    },
  
    // Detect if user wants to send email
// Detect if user wants to send email - FIXED VERSION
detectIntent(userInput) {
    const input = userInput.toLowerCase();
    
    // Check for stronger intent patterns first
    const strongIntents = {
      HIRE: [
        'i want to hire',
        'looking to hire',
        'hire him',
        'recruit him',
        'job opportunity',
        'job opening',
        'position available',
        'we are hiring',
        'interested in hiring'
      ],
      COLLABORATE: [
        'want to collaborate',
        'collaborate with',
        'work together',
        'partnership opportunity',
        'collaborate on project',
        'joint project'
      ],
      QUESTION: [
        'i want to contact',
        'want to ask him',
        'send him a message',
        'reach out to him',
        'get in touch',
        'contact laxman'
      ]
    };
  
    // First check strong patterns (multi-word phrases)
    for (const [type, phrases] of Object.entries(strongIntents)) {
      if (phrases.some(phrase => input.includes(phrase))) {
        console.log('📧 Email intent detected:', type, '(strong match)');
        return type;
      }
    }
  
    // Only check single keywords if they appear with action words
    const actionWords = ['want', 'need', 'looking', 'interested', 'can you', 'could you'];
    const hasActionWord = actionWords.some(word => input.includes(word));
  
    if (hasActionWord) {
      const weakIntents = {
        HIRE: ['hire', 'recruit', 'position'],
        COLLABORATE: ['collaborate', 'partnership'],
        QUESTION: ['contact', 'message', 'email', 'reach']
      };
  
      for (const [type, keywords] of Object.entries(weakIntents)) {
        if (keywords.some(kw => input.includes(kw))) {
          console.log('📧 Email intent detected:', type, '(weak match with action)');
          return type;
        }
      }
    }
  
    console.log('📧 No email intent detected');
    return null;
  },
    
    // Start email collection
    startCollection(inquiryType) {
      const flow = this.inquiryFlows[inquiryType];
      if (!flow) return null;
  
      this.conversationState = {
        isCollecting: true,
        inquiryType: inquiryType,
        data: {},
        currentStep: 0,
        flow: flow,
        useForm : true 
      };
  
      return {
        response: `Perfect! I'll open a form for you to fill in your details.`,
        action: 'OPEN_EMAIL_FORM', // ✅ NEW ACTION
        inquiryType: inquiryType
      };
    },
    
  // NEW: Handle form submission
handleFormSubmit(formData) {
    this.conversationState.data = formData;
    return this.sendEmail(this.conversationState.inquiryType, formData);
  },

    // Process user's answer
    processAnswer(userAnswer) {
      const { flow, currentStep, data } = this.conversationState;
      const currentField = flow.steps[currentStep];
  
      // Validate based on field
      if (currentField === 'email' && !this.validateEmail(userAnswer)) {
        return {
          response: "That doesn't look like a valid email. Could you provide it again?",
          action: 'RETRY'
        };
      }
  
      // Store data
      data[currentField] = userAnswer === 'skip' ? 'Not provided' : userAnswer;
  
      // Move to next step
      this.conversationState.currentStep++;
  
      // Check if done
      if (this.conversationState.currentStep >= flow.steps.length) {
        return this.confirmAndSend();
      }
  
      // Ask next question
      const nextField = flow.steps[this.conversationState.currentStep];
      return {
        response: flow.prompts[nextField],
        action: 'CONTINUE_COLLECTION'
      };
    },
  
    // Validate email
    validateEmail(email) {
      const regex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
      return regex.test(email);
    },
  
    // Confirm before sending
    confirmAndSend() {
      const { flow, data, inquiryType } = this.conversationState;
      
      return {
        response: flow.confirmMessage(data),
        action: 'CONFIRM_EMAIL',
        onConfirm: () => this.sendEmail(inquiryType, data)
      };
    },
  
    // Send email via EmailJS
    async sendEmail(inquiryType, data) {
      try {
        const templateParams = {
          from_name: data.name || 'Anonymous',
          reply_to: data.email || 'no-reply@example.com',
          phone: data.phone || 'Not provided',
          company: data.company || 'Not specified',
          project: data.project || 'N/A',
          message: data.message || 'No message provided',
          inquiry_type: inquiryType,
          timestamp: new Date().toLocaleString()
        };
  
        const response = await window.emailjs.send(
          this.config.serviceId,
          this.config.templateId,
          templateParams
        );
  
        console.log('✅ Email sent successfully:', response);
  
        // Reset state
        this.conversationState = {
          isCollecting: false,
          inquiryType: null,
          data: {},
          currentStep: 0
        };
  
        return {
          success: true,
          response: "Email sent successfully! Laxman will get back to you soon. Anything else I can help with?",
          action: 'EMAIL_SENT'
        };
  
      } catch (error) {
        console.error('❌ Email send failed:', error);
        
        return {
          success: false,
          response: "Oops! Email failed to send. You can reach Laxman directly at laxmankethavath5@gmail.com",
          action: 'EMAIL_FAILED'
        };
      }
    },
  
    // Cancel collection
    cancel() {
      this.conversationState = {
        isCollecting: false,
        inquiryType: null,
        data: {},
        currentStep: 0
      };
      
      return {
        response: "Okay, cancelled. What else can I help you with?",
        action: 'CANCELLED'
      };
    }
  };
  
  export default EmailAgent;